#include <stdio.h>
#include <string.h>
#include <ctype.h>

#define MAX_LENGTH 1000

/* Function prototypes */
void normalizeKeyword(char *keyword);
int charToNum(char ch);
char numToChar(int n);
void vigenereEncrypt(char *plaintext, char *keyword, char *ciphertext);
void vigenereDecrypt(char *ciphertext, char *keyword, char *plaintext);

/* Convert character to number: A=0, B=1, ..., Z=25 */
int charToNum(char ch) {
    return toupper(ch) - 'A';
}

/* Convert number to character: 0=A, 1=B, ..., 25=Z */
char numToChar(int n) {
    return (n % 26) + 'A';
}

/* Normalize keyword: uppercase and remove non-letters */
void normalizeKeyword(char *keyword) {
    int i, j = 0;
    char temp[MAX_LENGTH];

    for (i = 0; keyword[i] != '\0'; i++) {
        if (isalpha(keyword[i])) {
            temp[j++] = toupper(keyword[i]);
        }
    }
    temp[j] = '\0';
    strcpy(keyword, temp);
}

/* Encrypt using Vigenère cipher
 * Formula: C_i = (P_i + K_{i mod m}) mod 26
 */
void vigenereEncrypt(char *plaintext, char *keyword, char *ciphertext) {
    int m = strlen(keyword);
    int i;

    if (m == 0) {
        ciphertext[0] = '\0';
        return;
    }

    for (i = 0; plaintext[i] != '\0'; i++) {
        if (isalpha(plaintext[i])) {
            int pVal = charToNum(plaintext[i]);
            int kVal = charToNum(keyword[i % m]);
            int cVal = (pVal + kVal) % 26;

            /* Preserve lowercase/uppercase */
            if (islower(plaintext[i])) {
                ciphertext[i] = tolower(numToChar(cVal));
            } else {
                ciphertext[i] = numToChar(cVal);
            }
        } else {
            /* Preserve non-alphabetic characters */
            ciphertext[i] = plaintext[i];
        }
    }
    ciphertext[i] = '\0';
}

/* Decrypt using Vigenère cipher
 * Formula: P_i = (C_i - K_{i mod m} + 26) mod 26
 */
void vigenereDecrypt(char *ciphertext, char *keyword, char *plaintext) {
    int m = strlen(keyword);
    int i;

    if (m == 0) {
        plaintext[0] = '\0';
        return;
    }

    for (i = 0; ciphertext[i] != '\0'; i++) {
        if (isalpha(ciphertext[i])) {
            int cVal = charToNum(ciphertext[i]);
            int kVal = charToNum(keyword[i % m]);
            /* Add 26 before mod to handle negative values */
            int pVal = (cVal - kVal + 26) % 26;

            /* Preserve lowercase/uppercase */
            if (islower(ciphertext[i])) {
                plaintext[i] = tolower(numToChar(pVal));
            } else {
                plaintext[i] = numToChar(pVal);
            }
        } else {
            plaintext[i] = ciphertext[i];
        }
    }
    plaintext[i] = '\0';
}

int main() {
    char plaintext[MAX_LENGTH] = "ATTACKATDAWN";
    char keyword[MAX_LENGTH] = "LEMON";
    char ciphertext[MAX_LENGTH];
    char decrypted[MAX_LENGTH];

    /* Normalize keyword */
    normalizeKeyword(keyword);

    printf("========================================\n");
    printf("VIGENÈRE CIPHER - C IMPLEMENTATION\n");
    printf("========================================\n\n");

    printf("Plaintext:  %s\n", plaintext);
    printf("Keyword:    %s\n", keyword);

    /* Encrypt */
    vigenereEncrypt(plaintext, keyword, ciphertext);
    printf("Ciphertext: %s\n", ciphertext);

    /* Decrypt */
    vigenereDecrypt(ciphertext, keyword, decrypted);
    printf("Decrypted:  %s\n", decrypted);

    /* Additional example with lowercase */
    printf("\n------------------------------------------\n");

    strcpy(plaintext, "hello world");
    strcpy(keyword, "key");
    normalizeKeyword(keyword);

    printf("\nPlaintext:  %s\n", plaintext);
    printf("Keyword:    %s\n", keyword);

    vigenereEncrypt(plaintext, keyword, ciphertext);
    printf("Ciphertext: %s\n", ciphertext);

    vigenereDecrypt(ciphertext, keyword, decrypted);
    printf("Decrypted:  %s\n", decrypted);

    return 0;
}
